export default function SvgIcon({ name, size = 22, color = 'currentColor', style = {} }) {
  // Theme icon has its own SVG (different viewBox)
  if (name === 'theme') {
    const T = ICONS.theme;
    return T({ size, color, style });
  }
  const paths = ICONS[name];
  if (!paths) return null;
  return (
    <svg
      width={size} height={size}
      viewBox="0 0 24 24"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      style={{ color, display:'block', flexShrink:0, ...style }}
    >
      {paths}
    </svg>
  );
}
